                          <span style={{ color: 'var(--green)', fontWeight: 700, fontSize: 13 }}>{l.price?.toLocaleString()} RWF</span>
                          <span>{l.sector}</span>
                          <span>{l.date}</span>
                          <span>{l.views || 0} views</span>
                        </div>
                      </div>
                    </div>
                    <div style={{ display: 'flex', gap: 8, marginTop: 14, flexWrap: 'wrap' }}>
                      {isPending && <>
